      </div>
    </div>
  </div>
</template>

<script setup>
import { ref } from 'vue';
import { useRouter } from 'vue-router';
import axios from 'axios';
import { useLanguage } from '@/core/i18n/index.js';

const router = useRouter();


const { currentLocale, switchLanguage } = useLanguage();

const isLangMenuOpen = ref(false);

const availableLanguages = [
  { code: 'pt', label: 'Português 🇧🇷' },
  { code: 'en', label: 'English 🇺🇸' },
  { code: 'id', label: 'Bahasa Indonesia 🇮🇩' },
  { code: 'ar', label: 'العربية 🇸🇦' }
];

const selectLanguage = (code) => {
  currentLocale.value = code;
  switchLanguage();
  isLangMenuOpen.value = false;
};

const username = ref('');
const password = ref('');
const showPassword = ref(false);
const isLoading = ref(false);
const errorMessage = ref('');

const handleLogin = async () => {
  errorMessage.value = '';
  isLoading.value = true;
  
  const params = new URLSearchParams();
  params.append('username', username.value); 
  params.append('password', password.value);

  try {
    const response = await axios.post('/token', params);
    
    if (response.data.access_token) {
      localStorage.setItem("access_token", response.data.access_token);
      localStorage.setItem("username", username.value);
      router.push('/offboarding'); 
    } else {
      errorMessage.value = "Token not received by the server";
    }
  } catch (error) {
    console.error(error);
    if (error.response && error.response.status === 401) {
      errorMessage.value = "Incorrect username or password";
    } else {
      errorMessage.value = "Connection error";
    }
  } finally {
    isLoading.value = false;
  }
};
</script>